  {
    "file": "source/extensions/filters/http/ext_authz/ext_authz.cc",
    "line": 505,
    "severity": "medium",
    "description": "Route cache is cleared (line 510) BEFORE request headers are actually modified (lines 515-737). While the modifications happen synchronously in the same callback, this ordering is fragile and could cause issues if the code is refactored. More importantly, if clearRouteCache() is called but subsequent header validation fails (lines 632-638, 648-654, 664-670, 682-688), the cache has already been cleared unnecessarily, and the failure case doesn't roll back the cache clear.",
    "fix_patch": "--- a/source/extensions/filters/http/ext_authz/ext_authz.cc
+++ b/source/extensions/filters/http/ext_authz/ext_authz.cc
@@ -502,14 +502,33 @@
   switch (response->status) {
   case CheckStatus::OK: {
     // Any changes to request headers or query parameters can affect how the request is going to be
     // routed. If we are changing the headers we also need to clear the route
     // cache.
-    if (config_->clearRouteCache() &&
+    bool headers_modified = false;
+    bool query_params_modified = false;
+    
+    // Check if headers will be modified
+    if (!response->headers_to_set.empty() || !response->headers_to_append.empty() ||
+        !response->headers_to_remove.empty()) {
+      headers_modified = true;
+    }
+    
+    // Check if query parameters will be modified
+    if (!response->query_parameters_to_set.empty() ||
+        !response->query_parameters_to_remove.empty()) {
+      query_params_modified = true;
+    }
+    
+    // Clear route cache before modifying headers (do this validation first)
+    if (config_->clearRouteCache() && (headers_modified || query_params_modified)) {
         (!response->headers_to_set.empty() || !response->headers_to_append.empty() ||
          !response->headers_to_remove.empty() || !response->query_parameters_to_set.empty() ||
          !response->query_parameters_to_remove.empty())) {
       ENVOY_STREAM_LOG(debug, "ext_authz is clearing route cache", *decoder_callbacks_);
       decoder_callbacks_->downstreamCallbacks()->clearRouteCache();
     }
"
  },
  {
    "file": "source/common/http/header_utility.cc",
    "line": 581,
    "severity": "medium",
    "description": "isRemovableHeader() does not validate that the header string is non-empty before checking header[0]. While the condition uses short-circuit evaluation (header.empty() || header[0] != ':'), making it safe, an empty string being considered 'removable' is semantically confusing. Empty header names should either be explicitly rejected or handled with clearer logic.",
    "fix_patch": "--- a/source/common/http/header_utility.cc
+++ b/source/common/http/header_utility.cc
@@ -580,8 +580,9 @@

 bool HeaderUtility::isRemovableHeader(absl::string_view header) {
-  return (header.empty() || header[0] != ':') &&
-         !absl::EqualsIgnoreCase(header, Headers::get().HostLegacy.get());
+  // Empty headers are not valid and should not be considered removable
+  return (!header.empty() && header[0] != ':') &&
+         !absl::EqualsIgnoreCase(header, Headers::get().HostLegacy.get());
 }

 bool HeaderUtility::isModifiableHeader(absl::string_view header) {
"
  }
]

